INSERT INTO monitor_replay_session (
  project_id, replay_id, session_id, page_id, app_name, app_version, `release`, environment,
  user_id, device_id, initial_url, title, started_at, last_seen_at, chunk_count, event_count
) VALUES (
  #{projectId}, #{replayId}, #{sessionId}, #{pageId}, #{appName}, #{appVersion}, #{release}, #{environment},
  #{userId}, #{deviceId}, #{initialUrl}, #{title}, #{startedAt}, #{lastSeenAt}, #{chunkCount}, #{eventCount}
)

INSERT INTO monitor_replay_chunk (
  replay_session_id, sequence_no, started_at, ended_at, event_count, payload_json
) VALUES (
  #{replaySessionId}, #{sequenceNo}, #{startedAt}, #{endedAt}, #{eventCount}, #{payloadJson}
)
